  ('343f81f4-d949-497b-8df7-25bd444f5e15', 'College West', '897 College St', 'Toronto', 'ON', 43.6537159, -79.4248284, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/343f81f4-d949-497b-8df7-25bd444f5e15.jpg?t=1771969589635', 2024, 89, 'Roxborough', 'Condo', NULL, 'https://www.collegewest.com/suites', '{"scroll": true, "strategy": "playwright_render", "pre_capture_js": "(async function() { function delay(ms) { return new Promise(function(r) { setTimeout(r, ms); }); } function click(el) { el.dispatchEvent(new MouseEvent(\"click\", {bubbles: true, cancelable: true})); } function walkText(root) { var walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT); var text = \"\"; var node; while (node = walker.nextNode()) { var p = node.parentElement; if (p && (p.tagName === \"STYLE\" || p.tagName === \"SCRIPT\")) continue; var t = node.textContent.trim(); if (t.length > 1) text += t + \" \"; } return text.replace(/\\s+/g, \" \").trim(); } var allFpn = document.querySelectorAll(\"floorplan-navigator\"); var fpn1 = null; var fpn2 = null; allFpn.forEach(function(f) { if (f.classList.contains(\"fpn-modal\")) { fpn1 = f; } else { fpn2 = f; } }); if (!fpn1) fpn1 = allFpn[0]; if (!fpn1 || !fpn1.shadowRoot) return; var sr1 = fpn1.shadowRoot; var sr2 = fpn2 ? fpn2.shadowRoot : null; var floors = sr1.querySelectorAll(\"li.unit-filters__floor\"); if (!floors.length) return; var allResults = []; for (var i = 0; i < floors.length; i++) { click(floors[i]); await delay(1500); var svgUnits = sr1.querySelectorAll(\".unit--available-on\"); for (var j = 0; j < svgUnits.length; j++) { click(svgUnits[j]); await delay(2000); if (sr2) { var detail = walkText(sr2); if (detail.length > 10) { var cleaned = detail.split(\"Enlarge\")[0].trim(); if (cleaned.length > 5) allResults.push(cleaned); } } } } if (allResults.length > 0) { var div = document.createElement(\"div\"); div.id = \"collegewest-units\"; div.textContent = allResults.join(\"\\n---\\n\"); document.body.appendChild(div); } })()", "initial_wait_ms": 8000}'::jsonb, TRUE, '2026-02-24T18:17:36.619476+00:00'),
