  ('4c0edd77-97e6-45ce-9693-8c2489fd4e42', 'The Diamond', '980 Lansdowne Ave', 'Toronto', 'ON', 43.6697888, -79.4478552, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/4c0edd77-97e6-45ce-9693-8c2489fd4e42.jpg?t=1771971904092', 2026, 960, 'Davmark', 'Condo', NULL, 'https://www.diamondrentals.ca/suites', '{"scroll": true, "strategy": "playwright_render", "pre_capture_js": "(async function() { var host = document.querySelector(''floorplan-navigator''); if (!host || !host.shadowRoot) return; var sr = host.shadowRoot; var floors = sr.querySelectorAll(''li.unit-filters__floor''); if (!floors.length) return; var allText = []; for (var i = 0; i < floors.length; i++) { floors[i].dispatchEvent(new MouseEvent(''click'', {bubbles: true})); await new Promise(function(r) { setTimeout(r, 1500); }); var waited = 0; while (waited < 2000) { var listing = sr.querySelector(''.unit-listing__ul''); if (listing) { var t = listing.textContent.trim().replace(/\\s+/g, '' ''); if (t.length > 10) break; } await new Promise(function(r) { setTimeout(r, 200); }); waited += 200; } var listing = sr.querySelector(''.unit-listing__ul''); if (listing) { var t = listing.textContent.trim().replace(/\\s+/g, '' ''); if (t.length > 10) { var floorLabel = floors[i].textContent.trim(); allText.push(''FLOOR '' + floorLabel + '': '' + t); } } } if (allText.length > 0) { var div = document.createElement(''div''); div.id = ''diamond-units''; div.textContent = allText.join(''\\n''); document.body.appendChild(div); } })()", "extraction_hint": "This site has units across multiple floors. The pre_capture_js iterates ALL floors and appends unit listings in a diamond-units div. Extract EVERY unit from EVERY floor - there should be 80-120+ units total across all floors. Do not skip any floor sections.", "initial_wait_ms": 8000}'::jsonb, TRUE, '2026-02-24T18:17:36.619476+00:00'),
  ('53faa6bb-8e9c-4667-9a6e-744d72d60385', 'Serra', '1124 Rue de Bleury', 'Montreal', 'QC', 45.5048647, -73.5642776, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/53faa6bb-8e9c-4667-9a6e-744d72d60385.jpg?t=1771955518184', 2023, 245, 'Divco', 'PBR', NULL, NULL, '{}'::jsonb, TRUE, '2026-02-22T23:28:04.833678+00:00'),
