  ('a3ddadb6-dc08-4e51-a504-e8d186e26f40', 'Mirvish Village', '748 Bathurst St', 'Toronto', 'ON', 43.6643908, -79.411112, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a3ddadb6-dc08-4e51-a504-e8d186e26f40.jpg?t=1771464073758', 2024, 916, 'Westbank', 'PBR', 'https://living.westbankcorp.com/property/mirvish-village/', 'https://mirvish-residential-rentcafewebsite.securecafe.com/onlineleasing/mirvish-residential/floorplans', '{"notes": "RentCafe/Yardi (securecafe.com). Main page has plan types. Additional URL fetches all individual units. No sqft available.", "scroll": true, "strategy": "playwright_render", "scroll_count": 10, "additional_urls": ["https://mirvish-residential-rentcafewebsite.securecafe.com/onlineleasing/mirvish-residential/availableunits.aspx?myOlePropertyId=1602120"], "extraction_hint": "The ADDITIONAL PAGE section contains individual apartment units grouped by floor plan type. Extract EACH individual apartment (e.g. #B3-330, #B3-524, #4-13-03) as a separate unit with its specific rent. The unit_type comes from the Floor Plan header above each group (Studio = bachelor, 1 Bedroom = 1-bed, 1 Bedroom plus Den = 1-bed+den, 2 bedroom 1 bath = 2-bed, 2 bedroom 2 bath = 2-bed, 3 Bedrooms = 3-bed, Finished studio = bachelor). Do NOT extract the plan type summaries from the main page - only extract individual apartment units.", "initial_wait_ms": 5000}'::jsonb, TRUE, '2026-02-18T13:56:30.68652+00:00'),
