  ('a71141df-5893-4c11-99ab-250caa330263', 'Sloane - Tower A/B', '3450 Dufferin Ave', 'Toronto', 'ON', 43.7282, -79.4502, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a71141df-5893-4c11-99ab-250caa330263.jpg?t=1771970873921', 2025, 518, 'Fitzrovia', 'PBR', 'https://www.sloanelife.ca/suites', 'https://www.sloanelife.ca/suites', '{"scroll": true, "strategy": "playwright_render", "click_repeat": true, "scroll_count": 5, "section_clicks": ["button:has-text(\"WEST TOWER\")", "button:has-text(\"EAST TOWER\")"], "click_selectors": ["button:has-text(\"LOAD MORE\")"], "initial_wait_ms": 5000, "section_wait_ms": 3000, "max_click_repeats": 30}'::jsonb, TRUE, '2026-02-22T00:38:27.702126+00:00'),
  ('a8a53edb-f7ea-46be-8cad-57d81e95fd0c', 'Akoya Living', '55 Broadway Ave', 'Toronto', 'ON', 43.7114776, -79.3895027, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a8a53edb-f7ea-46be-8cad-57d81e95fd0c.jpg?t=1771350933044', 2025, 398, 'Times Group', 'PBR', NULL, 'https://www.akoyaliving.ca/suites', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 5, "wait_selector": "[class*=''suite''], [class*=''unit''], [class*=''listing'']", "pre_capture_js": "\n(async () => {\n  // Click Load More until gone\n  for (let i = 0; i < 20; i++) {\n    const btns = document.querySelectorAll(''button.uk3-button-default'');\n    let clicked = false;\n    for (const btn of btns) {\n      if (btn.textContent.toLowerCase().includes(''load'')) {\n        btn.click();\n        clicked = true;\n        break;\n      }\n    }\n    if (!clicked) break;\n    await new Promise(r => setTimeout(r, 2000));\n  }\n  await new Promise(r => setTimeout(r, 2000));\n\n  // Read all unit-group-card textContent (hidden from innerText)\n  const cards = document.querySelectorAll(''.unit-group-card'');\n  const modals = document.querySelectorAll(''.unit-group-modal'');\n  let text = ''[UNIT LISTINGS]\\n'';\n  for (const card of cards) {\n    const t = card.textContent.trim();\n    if (t) text += t + ''\\n---\\n'';\n  }\n  for (const modal of modals) {\n    const t = modal.textContent.trim();\n    if (t.length > 50) text += ''[MODAL]\\n'' + t + ''\\n---\\n'';\n  }\n  text += ''[/UNIT LISTINGS]\\n'';\n\n  // Inject as visible div so innerText capture picks it up\n  const div = document.createElement(''div'');\n  div.id = ''scraper-injected'';\n  div.textContent = text;\n  document.body.prepend(div);\n})()\n", "initial_wait_ms": 10000}'::jsonb, TRUE, '2026-02-13T19:12:54.105789+00:00'),
  ('a8e26f5b-15f1-4526-acdd-1156cb7479b0', 'Pivot', '35 Green Field Ave', 'Toronto', 'ON', 43.745, -79.47, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a8e26f5b-15f1-4526-acdd-1156cb7479b0.jpg?t=1771970444062', 2020, 355, 'Rhapsody', 'PBR', 'https://www.livingatpivot.com/floorplans', 'https://www.livingatpivot.com/floorplans', '{"strategy": "modal_iterate", "close_method": ".modal .close", "modal_wait_ms": 2000, "modal_selector": "#suite_details.modal.in", "initial_wait_ms": 5000, "trigger_selector": "button.suite-details-modal-btn"}'::jsonb, TRUE, '2026-02-22T00:38:27.702126+00:00'),
  ('a95f20c2-288b-46b3-86a2-4b6f867e3508', 'Chroma', '1888 Scotia St', 'Vancouver', 'BC', 49.2677304, -123.0975104, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a95f20c2-288b-46b3-86a2-4b6f867e3508.jpg?t=1776640578722', 2025, 133, 'Wave Developments', 'PBR', NULL, 'https://chromavancouver.ca/floorplans.html', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 5, "building_name": "Chroma", "additional_urls": ["https://chromavancouver.ca/"], "extraction_hint": "This site shows 8 floor plan TYPES only (Flat A, Flat A1, Flat B1, Flat B2, Flat B3, Loft A, Loft B, Loft C) with a STARTING rent per type shown as STARTING AT: $X / MONTH. Extract one row per floor plan type, setting rent_price to that starting rent. unit_count must be null (this is plan-type data, not individual unit listings). Square footage comes from the [SQFT REFERENCE] block; if a plan shows a sqft range (e.g. 450-520 sqft), use the AVERAGE. Bedroom mapping: Flat A and Flat A1 = Studio (bedrooms=0); Flat B1/B2/B3 = 1-bed; Loft A/B/C = 2-bed.", "initial_wait_ms": 8000, "vision_enrichment": {"mode": "image_urls", "enabled": true, "image_attr": "href", "max_images": 10, "tile_selector": ".fp-item-img-wrapper a[data-fancybox=\"plans\"]", "initial_wait_ms": 8000}}'::jsonb, TRUE, '2026-03-20T03:32:43.237415+00:00'),
  ('a9ad5da1-b5b2-4652-afac-3d6b6d965efb', 'XO Condos', '270 Dufferin St', 'Toronto', 'ON', 43.638427, -79.4272934, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a9ad5da1-b5b2-4652-afac-3d6b6d965efb.jpg?t=1771970760807', 2023, 293, 'Pinedale Properties', 'Condo', NULL, 'https://condos.ca/toronto/xo-condos-270-dufferin-st', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 10, "pre_capture_js": "(async function() { var elems = document.querySelectorAll(''a, button, span, div''); for (var i = 0; i < elems.length; i++) { if (elems[i].textContent.trim().match(/^Show All/)) { elems[i].click(); await new Promise(function(r) { setTimeout(r, 1500); }); } } window.scrollTo(0, document.body.scrollHeight); await new Promise(function(r) { setTimeout(r, 2000); }); })()", "initial_wait_ms": 8000}'::jsonb, TRUE, '2026-02-24T15:15:19.902107+00:00'),
  ('a9c23d45-d0b3-4dd3-8b1b-cdf2da2b27d9', '203 Residences', '203 Jarvis St', 'Toronto', 'ON', 43.6556602, -79.3735932, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/a9c23d45-d0b3-4dd3-8b1b-cdf2da2b27d9.jpg?t=1771463811702', 2024, 179, 'BGO', 'PBR', 'https://www.rent203residences.com', 'https://www.rent203residences.com/suites', '{"notes": "RentSync site (BGO). Card-based listings with Load More button. Same pattern as Elm Ledbury.", "scroll": true, "strategy": "playwright_render", "click_repeat": true, "scroll_count": 5, "click_selectors": ["button:has-text(\"Load More\")"], "initial_wait_ms": 5000, "max_click_repeats": 10}'::jsonb, TRUE, '2026-02-18T17:46:30.560985+00:00'),
