  ('af769afd-e20f-46e9-aa26-797eae4037d5', '185 Enfield', '185 Enfield Pl', 'Mississauga', 'ON', 43.591592, -79.634405, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/af769afd-e20f-46e9-aa26-797eae4037d5.jpg?t=1776639935050', 2025, 365, 'GWL', 'PBR', NULL, 'https://www.gwlraresidential.com/apartments/on/mississauga/one-eighty-five/floorplans', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 5, "pre_capture_js": "document.querySelectorAll(''[data-floorplan-name]'').forEach(el => { const name = el.getAttribute(''data-floorplan-name''); const sqft = el.getAttribute(''data-floorplan-sqft''); const price = el.getAttribute(''data-floorplan-price''); if (name && sqft) { const div = document.createElement(''div''); div.textContent = ''[PLAN DATA] '' + name + '' | Sqft: '' + sqft + '' | Price: '' + price; div.style.fontSize = ''14px''; el.parentElement.insertBefore(div, el); } });", "initial_wait_ms": 5000}'::jsonb, TRUE, '2026-03-20T03:32:54.158034+00:00'),
