  ('b5dec026-ffc2-4e24-8970-77491d2efb6f', 'Le Vanguard', '2000 Rue Saint-Marc', 'Montreal', 'QC', 45.4935056, -73.5821738, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/b5dec026-ffc2-4e24-8970-77491d2efb6f.jpg?t=1771970726393', 1975, 180, 'Baz', 'PBR', NULL, 'https://www.gmrre.com/residential/2000-saint-marc', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 5, "initial_wait_ms": 5000}'::jsonb, TRUE, '2026-02-24T15:15:19.902107+00:00'),
  ('b6e5960d-ba9b-4872-b02c-930bd616a139', 'The Forestwoods', '1547 Mississauga Vlg Blvd', 'Mississauga', 'ON', 43.5929043, -79.6284448, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/b6e5960d-ba9b-4872-b02c-930bd616a139.jpg?t=1776642576343', 1979, 300, 'Morguard', 'PBR', NULL, 'https://www.theforestwoods.com/floorplans', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 5, "initial_wait_ms": 5000}'::jsonb, TRUE, '2026-03-20T03:32:54.158034+00:00'),
  ('b802de60-2a59-417c-ad89-80fb54bb98ac', 'Archetype Residences', '220 E 1st Ave', 'Vancouver', 'BC', 49.2694242, -123.0448297, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/b802de60-2a59-417c-ad89-80fb54bb98ac.jpg?t=1776640506284', 2025, 215, 'Quadreal', 'PBR', NULL, 'https://quadrealresidential.com/vancouver/archetype-residences/floorplans/', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 8, "pre_capture_js": "\n(function(){\n  const blocks = document.querySelectorAll(''.popup-info-in'');\n  const lines = ['''', ''=== ARCHETYPE AVAILABLE UNIT LISTINGS ===''];\n  for (const p of blocks) {\n    const h = p.querySelector(''h3, h2'');\n    const planName = h ? h.textContent.trim().replace(/\\s+/g, '' '') : '''';\n    const beds = (p.querySelector(''.bedrooms'') ? p.querySelector(''.bedrooms'').textContent.trim().replace(/\\s+/g, '' '') : '''');\n    const baths = (p.querySelector(''.bathrooms'') ? p.querySelector(''.bathrooms'').textContent.trim().replace(/\\s+/g, '' '') : '''');\n    const sqft = (p.querySelector(''.sq-ft-range'') ? p.querySelector(''.sq-ft-range'').textContent.trim().replace(/\\s+/g, '' '') : '''');\n    const price = (p.querySelector(''.price-range'') ? p.querySelector(''.price-range'').textContent.trim().replace(/\\s+/g, '' '') : '''');\n    const rows = p.querySelectorAll(''table tr'');\n    const unitRows = [];\n    for (const r of rows) {\n      const cells = Array.from(r.querySelectorAll(''td'')).map(c => c.textContent.trim().replace(/\\s+/g, '' ''));\n      if (cells.length >= 3 && cells[0].startsWith(''#'')) {\n        unitRows.push(cells);\n      }\n    }\n    lines.push('''');\n    lines.push(''PLAN: '' + planName + '' | '' + beds + '' | '' + baths + '' | '' + sqft + '' | card price: '' + price);\n    lines.push(''Available units for this plan: '' + unitRows.length);\n    for (const u of unitRows) {\n      lines.push(''  Unit '' + u[0] + '' - sqft '' + u[1] + '' - rent '' + u[2]);\n    }\n  }\n  const pre = document.createElement(''pre'');\n  pre.id = ''archetype-units-dump'';\n  pre.style.cssText = ''position:relative;z-index:1;display:block;white-space:pre-wrap;font-family:monospace;padding:20px;'';\n  pre.textContent = lines.join(''\\n'');\n  document.body.appendChild(pre);\n})();\n", "extraction_hint": "This is a QuadReal / RentCafe marketing site. The top of the scraped text has floor-plan CARDS (one per plan: A1, A3 2, B1, B1 2, B1 3, B2, B5, B6 2, B8, B9, C1, C2, C3, D1, Penthouse 2, etc.) each with a plan name, bed/bath, sqft, and a \"Starting at $X / month\" or \"From $X to $Y / month\" range.\n\nBELOW THAT, under the marker \"=== ARCHETYPE AVAILABLE UNIT LISTINGS ===\", there is an injected plain-text dump containing EVERY individual available unit, grouped by plan. Each plan section looks like:\n\n  PLAN: <plan name> | <bedrooms> | <bathrooms> | <sqft> | card price: <range>\n  Available units for this plan: N\n    Unit #909 - sqft 320 - rent $2,125\n    Unit #1009 - sqft 320 - rent $2,125\n\nEXTRACTION RULES:\n1. EMIT ONE ROW PER INDIVIDUAL UNIT listed in the \"=== ARCHETYPE AVAILABLE UNIT LISTINGS ===\" section. Use the per-unit sqft and per-unit rent from that dump (NOT the card-level range).\n2. If a plan has zero \"Unit #...\" rows in the dump (e.g., C3 \"Call for details\"), SKIP that plan entirely — it has no available units.\n3. Do NOT emit extra rows from the top-of-page card grid — the dump below is authoritative for availability.\n4. For each unit row:\n   - unit_type: infer from the plan beds column (\"Studio\" → \"bachelor\", \"Studio + Den\" → \"bachelor\", \"1 Bed\" → \"1-bed\", \"1 Bed + Den\" → \"1-bed+den\", \"2 Bed\" → \"2-bed\", \"2 Bed + Den\" → \"2-bed+den\", \"3 Bed + Den\" → \"3-bed+den\", \"Penthouse 2 / 2 Bed\" → \"2-bed\")\n   - bathrooms: from the plan bath column (\"1 Bath\" → \"1\", \"2 Bath\" → \"2\")\n   - square_footage: the integer sqft from the unit row (e.g., 320, 457, 891)\n   - rent_price: the dollar amount from the unit row with $ and commas stripped (e.g., \"$2,125\" → 2125)\n   - rent_psf: rent_price / square_footage\n   - notes: plan name + unit number (e.g., \"Plan A3 2, Unit #909\")\n   - raw_text: short like \"Plan A3 2 #909 — 320 sqft — $2,125\"\n5. Ignore Matterport/3D Tour links, navigation, and footer text.", "initial_wait_ms": 6000}'::jsonb, TRUE, '2026-03-20T03:32:43.237415+00:00'),
  ('b95e9139-3a61-452a-ac19-79f11a71d877', 'Galleria 01 & 02', '1245 Dupont St', 'Toronto', 'ON', 43.6680916, -79.4409058, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/b95e9139-3a61-452a-ac19-79f11a71d877.jpg?t=1771970339083', 2026, 690, 'Almadev', 'Condo', NULL, NULL, NULL, TRUE, '2026-02-24T18:17:36.619476+00:00'),
