  ('e722cdb8-3d22-43bc-bd1e-012a4fa447b1', 'The Millway', '185 Millway', 'Vaughan', 'ON', 43.7977779, -79.5264561, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/e722cdb8-3d22-43bc-bd1e-012a4fa447b1.jpg?t=1771971939362', 2023, 366, 'Smart Living', 'PBR', 'https://themillway.ca/floor-plans/', 'https://themillway.ca/floor-plans/', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 3, "pre_capture_js": "(function(){function w(n,d,m){if(d>m)return\"\";var r=\"\";var c=n.children||[];for(var i=0;i<c.length;i++){var ch=c[i];if(ch.shadowRoot)r+=w(ch.shadowRoot,d+1,m);if(ch.children.length<=3){var t=ch.textContent?ch.textContent.trim():\"\";if(t&&t.length>1&&t.length<200&&t[0]!==\".\")r+=t+\"\\n\";}r+=w(ch,d,m);}return r;}var el=document.querySelector(\"rhenti-listings\");if(el&&el.shadowRoot){var div=document.createElement(\"div\");div.id=\"rhenti-extracted\";div.textContent=w(el.shadowRoot,0,5);document.body.appendChild(div);}})()", "initial_wait_ms": 8000}'::jsonb, TRUE, '2026-02-22T00:38:27.702126+00:00'),
  ('e776dc0f-72d5-4ebd-8cee-9926414c6f93', 'The Kay', '3610 Dixie Road', 'Mississauga', 'ON', 43.6429854, -79.6308531, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/e776dc0f-72d5-4ebd-8cee-9926414c6f93.jpg?t=1776642647372', 2022, 128, 'Killam Apartment REIT', 'PBR', NULL, 'https://livingatthekay.com', '{"scroll": true, "strategy": "playwright_render", "scroll_count": 5, "initial_wait_ms": 5000}'::jsonb, TRUE, '2026-03-20T03:32:54.158034+00:00'),
  ('eaa41d72-7ceb-456e-8a7f-bf3e5ec27cc3', 'West House', '88 Bathurst St', 'Toronto', 'ON', 43.6435691, -79.4028203, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/eaa41d72-7ceb-456e-8a7f-bf3e5ec27cc3.jpg?t=1771464253470', 2025, 307, 'Hines', 'PBR', 'https://www.westhouse.ca', 'https://sightmap.com/embed/1ywym6e1wq0', '{"notes": "SightMap embed. pre_capture_js fetches API JSON from __APP_CONFIG__.sightmaps[0].href (nested under json.data), formats all units with price as structured text. Fields: unit_number, area, price, floor_plan_id->bedroom_count/bathroom_count, floor_id->filter_label.", "strategy": "playwright_render", "pre_capture_js": "(async () => { try { const cfg = window.__APP_CONFIG__; if (!cfg || !cfg.sightmaps || !cfg.sightmaps[0]) { document.body.insertAdjacentHTML(\"beforeend\", \"<div>ERROR: __APP_CONFIG__.sightmaps not found</div>\"); return; } const apiUrl = cfg.sightmaps[0].href; const resp = await fetch(apiUrl); const json = await resp.json(); const d = json.data; const plans = {}; (d.floor_plans || []).forEach(p => { plans[p.id] = { name: p.name, beds: p.bedroom_count, baths: p.bathroom_count }; }); const floors = {}; (d.floors || []).forEach(f => { floors[f.id] = f.filter_label || f.filter_short_label; }); const lines = []; (d.units || []).forEach(u => { if (!u.price || u.price <= 0) return; const plan = plans[u.floor_plan_id] || {}; const floor = floors[u.floor_id] || \"?\"; const beds = plan.beds != null ? plan.beds : \"?\"; const baths = plan.baths != null ? plan.baths : \"?\"; const bedLabel = beds === 0 ? \"Studio\" : beds + \" Bed / \" + baths + \" Bath\"; const sqft = u.area ? u.area + \" sq. ft.\" : \"N/A\"; const rent = \"C$\" + u.price; lines.push(\"UNIT \" + (u.unit_number || \"?\") + \" | \" + bedLabel + \" | \" + sqft + \" | \" + rent + \" | \" + floor + \" | Plan: \" + (plan.name || \"?\")); }); const output = \"=== SIGHTMAP UNIT DATA ===\\n\" + lines.join(\"\\n\") + \"\\n=== END SIGHTMAP DATA === (\" + lines.length + \" available units)\"; const div = document.createElement(\"div\"); div.id = \"sightmap-extracted\"; div.style.whiteSpace = \"pre-wrap\"; div.textContent = output; document.body.appendChild(div); } catch(e) { document.body.insertAdjacentHTML(\"beforeend\", \"<div>ERROR: \" + e.message + \"</div>\"); } })()", "initial_wait_ms": 5000}'::jsonb, TRUE, '2026-02-18T17:46:30.560985+00:00'),
  ('eb384f15-38e8-4a11-89a4-ea8f311eb4d4', 'Parker', '200 Redpath Avenue', 'Toronto', 'ON', 43.7099696, -79.3936249, 'https://yckzayjlcvxinxcebyuf.supabase.co/storage/v1/object/public/comp-building-photos/eb384f15-38e8-4a11-89a4-ea8f311eb4d4.jpg', 2022, 349, 'Fitzrovia', 'PBR', NULL, 'https://www.parkerlife.ca/suites', '{"notes": "RentSync Levels view. All available units pre-rendered in DOM with .unit-item.available class. pre_capture_js extracts all available units text and injects into body.", "scroll": false, "strategy": "playwright_render", "pre_capture_js": "(async function() { var units = document.querySelectorAll(''.floor-container .unit-item.available''); if (!units.length) return; var allText = []; units.forEach(function(unit) { var name = unit.querySelector(''.name''); var rent = unit.querySelector(''.rent''); var beds = unit.querySelector(''.bedroom''); var baths = unit.querySelector(''.bathroom''); var sqft = unit.querySelector(''.sqft''); var avail = unit.querySelector(''.availability''); var parts = []; if (name) parts.push(name.textContent.trim()); if (rent) parts.push(rent.textContent.trim()); if (beds) parts.push(beds.textContent.trim()); if (baths) parts.push(baths.textContent.trim()); if (sqft) parts.push(sqft.textContent.trim()); if (avail) parts.push(avail.textContent.trim()); allText.push(parts.join('' | '')); }); var div = document.createElement(''div''); div.id = ''parker-units''; div.textContent = ''AVAILABLE UNITS ('' + units.length + ''):\\n'' + allText.join(''\\n''); document.body.appendChild(div); })()", "initial_wait_ms": 8000}'::jsonb, TRUE, '2026-02-16T19:37:30.442737+00:00'),
